// bundle-worker.js — concatenate v2_strip_packer + algorithm + orchestration
// (functions/index.js) into a single in-browser Web Worker script.
//
// Run with: node bundle-worker.js
//
// Output: optimizer-worker.js (KB-sized, no require, no firebase glue).
// The HTML's `<script id="inco-optimizer-worker-src">` block must then be
// replaced with the contents of optimizer-worker.js.
//
// The bundle order is:
//   1. v2_strip_packer.js   — strip helpers (consolidate, generateCandidates,
//                              rowsX/rowsY, genFileContent, etc.)
//   2. lib/algorithm.js     — setCoverBB + dominanceFilter
//   3. functions/index.js   — orchestration (runOptimizerCore + greedy +
//                              over-cover trim)
//   4. Worker entry point   — self.onmessage that calls runOptimizerCore.

const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, 'functions');
const read = (p) => fs.readFileSync(path.join(ROOT, p), 'utf8');

// ─── 1. v2_strip_packer.js ─────────────────────────────────────────────
//   - drop firebase requires + setGlobalOptions + the onCall export
//   - rename `runOptimizerCore` so it doesn't collide with index.js's
//     orchestration (which exports its own runOptimizerCore)
let v2 = read('v2_strip_packer.js');
v2 = v2
  .replace(/^const \{ onCall, HttpsError \} = require\('firebase-functions\/v2\/https'\);\s*$/m, '')
  .replace(/^const \{ setGlobalOptions \} = require\('firebase-functions\/v2'\);\s*$/m, '')
  .replace(/^setGlobalOptions\([\s\S]*?^\}\);\s*$/m, '')
  .replace(/^exports\.runOptimizer = onCall\([\s\S]*?^\s*\}\s*\);\s*$/m, '')
  .replace(/^exports\._test = .*$/m, '')
  .replace(/\brunOptimizerCore\b/g, 'v2_runOptimizerCore');

// ─── 2. algorithm.js ───────────────────────────────────────────────────
//   - drop the module.exports tail (single-line or multi-line forms)
let algo = read('lib/algorithm.js');
algo = algo
  .replace(/^module\.exports = \{[\s\S]*?^\};\s*$/m, '')
  .replace(/^module\.exports = \{[^}]*\};\s*$/m, '');

// ─── 3. orchestration (functions/index.js) ─────────────────────────────
//   - drop the firebase requires
//   - drop the require('./lib/v2packer') and require('./lib/algorithm')
//   - drop setGlobalOptions
//   - drop the onCall export and exports._test
//   - the `const { ... } = v2/algo` destructuring is left intact; since the
//     `v2` and `algo` symbols don't exist in the bundle, we drop those two
//     lines too — the helpers (consolidate, generateCandidates, rowsX,
//     rowsY, genFileContent, setCoverBB, dominanceFilter) are already at
//     top level from steps 1 & 2.
let orch = read('index.js');
orch = orch
  .replace(/^const \{ onCall, HttpsError \} = require\('firebase-functions\/v2\/https'\);\s*$/m, '')
  .replace(/^const \{ setGlobalOptions \}\s*= require\('firebase-functions\/v2'\);\s*$/m, '')
  .replace(/^setGlobalOptions\([\s\S]*?^\}\);\s*$/m, '')
  .replace(/^const v2 = require\('\.\/lib\/v2packer'\);\s*$/m, '')
  .replace(/^const algo = require\('\.\/lib\/algorithm'\);\s*$/m, '')
  // Strip any const-destructure of v2 / algo (single-line or multi-line).
  // Tolerates new fields added to either object — use [\s\S]*? rather than
  // listing exact field names so the bundle keeps building when index.js
  // adds destructured imports.
  .replace(/^const \{[\s\S]*?\}\s*=\s*v2;\s*$/m, '')
  .replace(/^const \{[\s\S]*?\}\s*=\s*algo;\s*$/m, '')
  .replace(/^exports\.runOptimizer = onCall\([\s\S]*?^\s*\}\s*\);\s*$/m, '')
  .replace(/^exports\._test = .*$/m, '');

// ─── 4. worker entry point ─────────────────────────────────────────────
const workerEntry = `
// ============================================================================
// Worker entry point
// ============================================================================
self.onmessage = async function(e) {
  const input = e.data;
  try {
    const validationErr = validateInput(input);
    if (validationErr) {
      self.postMessage({ type: 'error', code: 'invalid-argument', message: validationErr });
      return;
    }
    const result = await runOptimizerCore(input);
    self.postMessage({ type: 'result', result });
  } catch (err) {
    self.postMessage({
      type: 'error', code: 'internal',
      message: err.message || String(err),
      stack: err.stack,
    });
  }
};
`;

const HEADER = `// ═══════════════════════════════════════════════════════════════════════
// INCO Furniture — Optimizer Worker (auto-generated bundle)
// Generated by bundle-worker.js. DO NOT EDIT DIRECTLY.
// Re-bundle by running: node bundle-worker.js
//
// Contents:
//   * v2_strip_packer (consolidate, generateCandidates, rowsX/rowsY,
//     genFileContent, packXGreedy, packYGreedy, etc.) — firebase glue stripped
//   * algorithm.js   (setCoverBB, dominanceFilter, etc.)
//   * orchestration  (runOptimizerCore + greedy + over-cover trim)
//   * Worker entry point
// ═══════════════════════════════════════════════════════════════════════
`;

const bundle = HEADER + '\n' + v2 + '\n' + algo + '\n' + orch + '\n' + workerEntry;

// Sanity checks: the bundle must not require anything, must not have
// CommonJS exports, and must not reference deleted modules or firebase.
const banned = [
  [/\brequire\s*\(/,            'require() call'],
  [/\bmodule\.exports\b/,       'module.exports'],
  [/\bexports\.[A-Za-z]/,       'exports.X'],
  [/firebase-functions/,        'firebase-functions reference'],
  [/\bsetGlobalOptions\b/,      'setGlobalOptions call'],
  [/\bonCall\b/,                'onCall call'],
  [/strip-extractor/,           'strip-extractor reference (deleted)'],
  [/strip-renderer/,            'strip-renderer reference (deleted)'],
];
const warnings = [];
for (const [r, label] of banned) {
  if (r.test(bundle)) {
    console.error(`BUNDLE CONTAINS: ${label}`);
    warnings.push(label);
  }
}
if (warnings.length > 0) process.exit(1);

// Parse-check: ensure the bundle is a valid script. Catches redeclared
// identifiers (e.g. when an index.js destructure isn't stripped properly
// and shadows a top-level function from v2_strip_packer.js).
try {
  const wrapper = 'const self = { onmessage: null, postMessage: () => {} };\n' + bundle;
  new Function(wrapper);
} catch (e) {
  console.error('BUNDLE FAILS TO PARSE:', e.message);
  process.exit(1);
}

const out = path.join(__dirname, 'optimizer-worker.js');
fs.writeFileSync(out, bundle);
console.log(`Wrote ${out} (${(bundle.length/1024).toFixed(1)} KB, ${bundle.split('\n').length} lines)`);

// ─── 5. Minify with Terser ─────────────────────────────────────────────
// Produces optimizer-worker.min.js for embedding in the HTML.  We keep
// the un-minified copy too because:
//   * Easier to inspect / diff when iterating on the algorithm.
//   * Stack traces from the worker are readable in dev (the minified
//     copy is only embedded in production builds).
// Terser settings:
//   * compress.passes:2 — squeezes a bit more out of dead-code paths.
//   * mangle.toplevel:true — shortens top-level function names (we don't
//     reference them from outside the worker — the only entry is the
//     self.onmessage handler at the bottom — so this is safe).
//   * keepFnames:false — algorithms run in a hot loop; no debug names.
// Output goes to optimizer-worker.min.js.
const { execFileSync } = require('child_process');
const minOut = path.join(__dirname, 'optimizer-worker.min.js');
try {
  execFileSync('npx', [
    '--yes', 'terser',
    out,
    '--compress', 'passes=2',
    '--mangle', 'toplevel=true',
    '--format', 'comments=false',
    '--output', minOut,
  ], { stdio: ['ignore', 'inherit', 'inherit'], shell: process.platform === 'win32' });
  const minSize = fs.statSync(minOut).size;
  console.log(`Wrote ${minOut} (${(minSize/1024).toFixed(1)} KB, ` +
              `${(100 - 100 * minSize / bundle.length).toFixed(1)}% smaller)`);
} catch (e) {
  console.error('Terser minification failed:', e.message);
  console.error('  optimizer-worker.min.js was NOT written.');
  console.error('  Install Terser globally (npm i -g terser) or accept the un-minified bundle.');
  process.exit(1);
}

// ─── 6. Obfuscate with javascript-obfuscator ───────────────────────────
// Runs ON TOP OF the Terser output so we start from the most compact code
// possible.  Output goes to optimizer-worker.obf.js, which is what the
// installer prefers when present.
//
// Settings rationale (perf-tuned for a hot-loop algorithm — the strip
// packer does millions of property accesses; we removed the obfuscator
// options that would tax that hot path):
//   * stringArray + threshold 0.75 — strings still moved into an indexed
//     array (no `"typeId"`-style literal grepping), but
//   * stringArrayEncoding: NONE — strings are NOT base64-encoded.  Decoding
//     on every property access added 10-20% runtime; we lose only mild
//     readability friction since the array is still randomized.
//   * splitStrings: false — no runtime string-concat overhead.  Saved
//     5-10% per call.
//   * identifierNamesGenerator: 'hexadecimal' — `_0x4a2f`-style names.
//   * selfDefending: false — the tamper-check fires on every function
//     entry and cost 10-15% in this kernel.  Anyone who deliberately
//     reformats already beats it; it's near-zero protection.
//   * disableConsoleOutput — replaces console.* with no-ops.  Free win
//     (and the reverse-engineer loses the optimizer's timing breadcrumbs).
//   * NO controlFlowFlattening — would cost 30-50% runtime.
//   * NO deadCodeInjection — bloats the file with marginal protection.
//   * NO debugProtection — would break the operator's own devtools.
const obfOut = path.join(__dirname, 'optimizer-worker.obf.js');
try {
  execFileSync('npx', [
    '--yes', 'javascript-obfuscator',
    minOut,
    '--output', obfOut,
    '--compact', 'true',
    '--string-array', 'true',
    '--string-array-encoding', 'none',
    '--string-array-threshold', '0.75',
    '--split-strings', 'false',
    '--identifier-names-generator', 'hexadecimal',
    '--self-defending', 'false',
    '--disable-console-output', 'true',
    '--control-flow-flattening', 'false',
    '--dead-code-injection', 'false',
    '--debug-protection', 'false',
    '--unicode-escape-sequence', 'false',
    '--transform-object-keys', 'false',
    '--rename-globals', 'false',
  ], { stdio: ['ignore', 'inherit', 'inherit'], shell: process.platform === 'win32' });
  const obfSize = fs.statSync(obfOut).size;
  console.log(`Wrote ${obfOut} (${(obfSize/1024).toFixed(1)} KB, ` +
              `${(obfSize / bundle.length).toFixed(2)}x un-minified, ` +
              `${(obfSize / fs.statSync(minOut).size).toFixed(2)}x Terser-minified)`);
} catch (e) {
  console.error('javascript-obfuscator failed:', e.message);
  console.error('  optimizer-worker.obf.js was NOT written; installer will fall back to minified.');
  // Non-fatal: the installer prefers .obf.js but falls back to .min.js.
}
